-- 数据库初始化脚本（基础表结构）
CREATE TABLE IF NOT EXISTS sys_tenant (id BIGINT PRIMARY KEY, tenant_code VARCHAR(100) NOT NULL UNIQUE, tenant_name VARCHAR(255) NOT NULL, status VARCHAR(20) DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS sys_user (id BIGINT PRIMARY KEY, tenant_id BIGINT NOT NULL, username VARCHAR(100) NOT NULL, password VARCHAR(255) NOT NULL, status VARCHAR(20) DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, INDEX idx_tenant_id (tenant_id), UNIQUE KEY uk_tenant_username (tenant_id, username)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS seating_info (id BIGINT PRIMARY KEY, tenant_id BIGINT NOT NULL, seat_number VARCHAR(50) NOT NULL, status VARCHAR(20) DEFAULT 'available', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, INDEX idx_tenant_id (tenant_id), UNIQUE KEY uk_tenant_seat (tenant_id, seat_number)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
